// // When address is non-zero, output is all zeros; when address is zero, output is address followed by seven zeros.
module top_module(
    input [0:0] address,
    input clock,
    output reg [7:0] q
);always @(posedge clock) begin
    if (address == 0) begin
        q <= 0;
    end else begin
        q <= {address, 7'b0};
    end
end

endmodule
